     1→import React, { useEffect } from 'react';
     2→import { useEscapeKey } from '../hooks/useEscapeKey';
     3→
     4→interface ModalProps {
     5→  isOpen: boolean;
     6→  onClose: () => void;
     7→  title: string;
     8→  children: React.ReactNode;
     9→  maxWidth?: 'sm' | 'md' | 'lg' | 'xl' | '2xl';
    10→}
    11→
    12→/**
    13→ * Simple Modal component - minimal styling
    14→ */
    15→export const Modal: React.FC<ModalProps> = ({
    16→  isOpen,
    17→  onClose,
    18→  title,
    19→  children,
    20→  maxWidth = 'md',
    21→}) => {
    22→  // Handle escape key with high priority (z-9999)
    23→  useEscapeKey({ enabled: isOpen, onEscape: onClose, priority: 9999 });
    24→
    25→  // Handle body overflow
    26→  useEffect(() => {
    27→    if (isOpen) {
    28→      document.body.style.overflow = 'hidden';
    29→    }
    30→
    31→    return () => {
    32→      document.body.style.overflow = 'unset';
    33→    };
    34→  }, [isOpen]);
    35→
    36→  const maxWidthClasses = {
    37→    sm: 'max-w-sm',
    38→    md: 'max-w-md',
    39→    lg: 'max-w-lg',
    40→    xl: 'max-w-xl',
    41→    '2xl': 'max-w-2xl',
    42→  };
    43→
    44→  if (!isOpen) return null;
    45→
    46→  return (
    47→    <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4">
    48→      {/* Backdrop */}
    49→      <div
    50→        className="absolute inset-0 bg-black bg-opacity-50"
    51→        onClick={onClose}
    52→      />
    53→
    54→      {/* Modal */}
