/**
 * Task Summary Widget
 *
 * Shows overview of tasks: due today, in progress, completed
 */

import React from 'react';
import { BaseWidget } from './BaseWidget';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useNavigate } from 'react-router-dom';

export const TaskSummaryWidget: React.FC = () => {
  const { tasks } = useKanbanStore();
  const navigate = useNavigate();

  const dueToday = tasks.filter((t) => {
    if (!t.dueDate) return false;
    const due = new Date(t.dueDate);
    const today = new Date();
    return due.toDateString() === today.toDateString();
  });

  const inProgress = tasks.filter((t) => t.status === 'inprogress');
  const completed = tasks.filter((t) => t.status === 'done');

  return (
    <BaseWidget title="Tasks" icon="✅">
      <div className="space-y-4">
        <div className="grid grid-cols-3 gap-4">
          <div>
            <div className="text-3xl font-bold text-status-warning">{dueToday.length}</div>
            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">Due Today</div>
          </div>
          <div>
            <div className="text-3xl font-bold text-accent-blue">{inProgress.length}</div>
            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">In Progress</div>
          </div>
          <div>
            <div className="text-3xl font-bold text-status-success">{completed.length}</div>
            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary">Completed</div>
          </div>
        </div>
        <button
          onClick={() => navigate('/tasks')}
          className="w-full px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-lg font-medium transition-colors"
        >
          View All Tasks →
        </button>
      </div>
    </BaseWidget>
  );
};

/**
 * Quick Add Widget
 *
 * Quickly add tasks to your Kanban board
 */

import React, { useState } from 'react';
import { BaseWidget } from './BaseWidget';
import { useKanbanStore } from '../../stores/useKanbanStore';

export const QuickAddWidget: React.FC = () => {
  const { addTask } = useKanbanStore();
  const [input, setInput] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (input.trim()) {
      addTask({
        title: input.trim(),
        description: '',
        status: 'todo',
        priority: 'medium',
        tags: [],
        startDate: null,
        dueDate: null,
      });
      setInput('');
    }
  };

  return (
    <BaseWidget title="Quick Add" icon="➕">
      <form onSubmit={handleSubmit} className="space-y-3">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Add a task..."
          className="w-full px-4 py-2 border rounded-lg
                     bg-white dark:bg-surface-dark
                     text-text-light-primary dark:text-text-dark-primary
                     border-border-light dark:border-border-dark
                     focus:outline-none focus:ring-2 focus:ring-accent-blue"
        />
        <button
          type="submit"
          className="w-full px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-lg transition-colors"
        >
          Add Task
        </button>
        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
          Press Enter to add quickly
        </p>
      </form>
    </BaseWidget>
  );
};

import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useThemeStore } from '../stores/useThemeStore';

/**
 * Simple Header component - minimal styling
 */
export const Header: React.FC = () => {
  const { mode, toggleTheme } = useThemeStore();
  const location = useLocation();

  const isActive = (path: string) => location.pathname === path;

  return (
    <header className="sticky top-0 z-50 bg-white dark:bg-surface-dark border-b border-border-light dark:border-border-dark">
      <div className="container mx-auto px-4 py-3">
        {/* Top row: Branding + Controls */}
