          {/* Theme Toggle */}
          <button
            onClick={toggleTheme}
            className="p-2 rounded-lg border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated"
            title={`Switch to ${mode === 'dark' ? 'light' : 'dark'} mode`}
          >
            <span className="text-xl">
              {mode === 'dark' ? '☀️' : '🌙'}
            </span>
          </button>
        </div>

        {/* Navigation */}
        <nav className="flex items-center gap-2 overflow-x-auto">
          {[
            { to: '/', label: '🏠 Dashboard' },
            { to: '/notes', label: '📝 Notes' },
            { to: '/planning', label: '📅 Planning' },
            { to: '/tasks', label: '✓ Tasks' },
            { to: '/settings', label: '⚙️ Settings' },
          ].map(({ to, label }) => (
            <Link
              key={to}
              to={to}
              className={`
                px-3 py-2 rounded-lg text-sm font-medium
                ${
                  isActive(to)
                    ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
                }
              `}
            >
              {label}
            </Link>
          ))}
        </nav>
      </div>
    </header>
  );
};

