import React, { lazy, Suspense, useEffect, useState } from 'react';
import { indexedDBService } from '../services/indexedDB';
import { useWidgetStore } from '../stores/useWidgetStore';
import { WidgetManager } from '../components/WidgetManager';
import { PresetManager } from '../components/PresetManager';
import { BackgroundCustomizer, type BackgroundSettings } from '../components/BackgroundCustomizer';
import { SortableWidget } from '../components/SortableWidget';
// Masonry removed - using CSS Grid for proper column spanning support
import { DndContext, closestCenter, PointerSensor, useSensor, useSensors, DragOverlay } from '@dnd-kit/core';
import type { DragEndEvent, DragStartEvent } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy } from '@dnd-kit/sortable';

// Weather & Map widget
const WeatherMapWidget = lazy(() => import('../widgets/Dashboard/WeatherMapWidget').then(m => ({ default: m.WeatherMapWidget })));

// Lazy load dashboard widgets
const QuoteWidget = lazy(() => import('../widgets/Dashboard/QuoteWidget').then(m => ({ default: m.QuoteWidget })));
const CryptoWidget = lazy(() => import('../widgets/Dashboard/CryptoWidget').then(m => ({ default: m.CryptoWidget })));
const HackerNewsWidget = lazy(() => import('../widgets/Dashboard/HackerNewsWidget').then(m => ({ default: m.HackerNewsWidget })));
const FactsWidget = lazy(() => import('../widgets/Dashboard/FactsWidget').then(m => ({ default: m.FactsWidget })));
const GitHubWidget = lazy(() => import('../widgets/Dashboard/GitHubWidget').then(m => ({ default: m.GitHubWidget })));
const JokeWidget = lazy(() => import('../widgets/Dashboard/JokeWidget').then(m => ({ default: m.JokeWidget })));
const PomodoroWidget = lazy(() => import('../widgets/Dashboard/PomodoroWidget').then(m => ({ default: m.PomodoroWidget })));
const UnsplashWidget = lazy(() => import('../widgets/Dashboard/UnsplashWidget').then(m => ({ default: m.UnsplashWidget })));

// Core widgets
const TasksQuickAddWidget = lazy(() => import('../widgets/Dashboard/TasksQuickAddWidget').then(m => ({ default: m.TasksQuickAddWidget })));
const UpcomingEventsWidget = lazy(() => import('../widgets/Dashboard/UpcomingEventsWidget').then(m => ({ default: m.UpcomingEventsWidget })));
const RecentNotesWidget = lazy(() => import('../widgets/Dashboard/RecentNotesWidget').then(m => ({ default: m.RecentNotesWidget })));

// New widgets
const RedditWidget = lazy(() => import('../widgets/Dashboard/RedditWidget').then(m => ({ default: m.RedditWidget })));
const DevToWidget = lazy(() => import('../widgets/Dashboard/DevToWidget').then(m => ({ default: m.DevToWidget })));
const WordOfDayWidget = lazy(() => import('../widgets/Dashboard/WordOfDayWidget').then(m => ({ default: m.WordOfDayWidget })));
const CurrencyWidget = lazy(() => import('../widgets/Dashboard/CurrencyWidget').then(m => ({ default: m.CurrencyWidget })));
const WorldClockWidget = lazy(() => import('../widgets/Dashboard/WorldClockWidget').then(m => ({ default: m.WorldClockWidget })));
const IPInfoWidget = lazy(() => import('../widgets/Dashboard/IPInfoWidget').then(m => ({ default: m.IPInfoWidget })));
const QRCodeWidget = lazy(() => import('../widgets/Dashboard/QRCodeWidget').then(m => ({ default: m.QRCodeWidget })));
const ColorPaletteWidget = lazy(() => import('../widgets/Dashboard/ColorPaletteWidget').then(m => ({ default: m.ColorPaletteWidget })));

// New widgets - Phase 1
const CalculatorWidget = lazy(() => import('../widgets/Dashboard/CalculatorWidget').then(m => ({ default: m.CalculatorWidget })));
const UnitConverterWidget = lazy(() => import('../widgets/Dashboard/UnitConverterWidget').then(m => ({ default: m.UnitConverterWidget })));
const CountdownWidget = lazy(() => import('../widgets/Dashboard/CountdownWidget').then(m => ({ default: m.CountdownWidget })));
const ShortcutsWidget = lazy(() => import('../widgets/Dashboard/ShortcutsWidget').then(m => ({ default: m.ShortcutsWidget })));
const StockMarketWidget = lazy(() => import('../widgets/Dashboard/StockMarketWidget').then(m => ({ default: m.StockMarketWidget })));
const WikipediaWidget = lazy(() => import('../widgets/Dashboard/WikipediaWidget').then(m => ({ default: m.WikipediaWidget })));

// New widgets - Phase 2
const BoredWidget = lazy(() => import('../widgets/Dashboard/BoredWidget').then(m => ({ default: m.BoredWidget })));
const DictionaryWidget = lazy(() => import('../widgets/Dashboard/DictionaryWidget').then(m => ({ default: m.DictionaryWidget })));
// REMOVED: ProductHuntWidget (CORS issues, API requires auth)
const AINewsWidget = lazy(() => import('../widgets/Dashboard/AINewsWidget').then(m => ({ default: m.AINewsWidget })));
const AirQualityWidget = lazy(() => import('../widgets/Dashboard/AirQualityWidget').then(m => ({ default: m.AirQualityWidget })));
const PackageStatsWidget = lazy(() => import('../widgets/Dashboard/PackageStatsWidget').then(m => ({ default: m.PackageStatsWidget })));

// New widgets - Phase 3
const PixelArtWidget = lazy(() => import('../widgets/Dashboard/PixelArtWidget').then(m => ({ default: m.PixelArtWidget })));
const TypingTestWidget = lazy(() => import('../widgets/Dashboard/TypingTestWidget').then(m => ({ default: m.TypingTestWidget })));
const MemoryGameWidget = lazy(() => import('../widgets/Dashboard/MemoryGameWidget').then(m => ({ default: m.MemoryGameWidget })));
const MotivationalWidget = lazy(() => import('../widgets/Dashboard/MotivationalWidget').then(m => ({ default: m.MotivationalWidget })));
const GitHubTrendingWidget = lazy(() => import('../widgets/Dashboard/GitHubTrendingWidget').then(m => ({ default: m.GitHubTrendingWidget })));
const AwesomeListsWidget = lazy(() => import('../widgets/Dashboard/AwesomeListsWidget').then(m => ({ default: m.AwesomeListsWidget })));
const RepoStatsWidget = lazy(() => import('../widgets/Dashboard/RepoStatsWidget').then(m => ({ default: m.RepoStatsWidget })));
