const ClipboardWidget = lazy(() => import('../widgets/Dashboard/ClipboardWidget').then(m => ({ default: m.ClipboardWidget })));
const TabManagerWidget = lazy(() => import('../widgets/Dashboard/TabManagerWidget').then(m => ({ default: m.TabManagerWidget })));
const UptimeWidget = lazy(() => import('../widgets/Dashboard/UptimeWidget').then(m => ({ default: m.UptimeWidget })));

// Loading fallback
const WidgetLoader = () => (
  <div className="h-64 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg animate-pulse"></div>
);

// Widget props interface for dynamic instances
interface WidgetProps {
  widgetId?: string;
